#include <stdio.h>
#include <stdlib.h>

// Define the structure for a binary tree node
typedef struct TreeNode {
    int val;
    struct TreeNode* left;
    struct TreeNode* right;
} TreeNode;

// Function to create a new binary tree node
TreeNode* createTreeNode(int val) {
    TreeNode* newNode = (TreeNode*)malloc(sizeof(TreeNode));
    if (!newNode) {
        printf("Memory error
");
        return NULL;
    }
    newNode->val = val;
    newNode->left = newNode->right = NULL;
    return newNode;
}

// Function to calculate the maximum width of a binary tree
int widthOfBinaryTree(TreeNode* root) {
    if (!root) return 0;
    int maxWidth = 0;
    // Queue to store nodes and their indices
    typedef struct QueueNode {
        TreeNode* node;
        int index;
        struct QueueNode* next;
    } QueueNode;
    QueueNode* head = NULL;
    QueueNode* tail = NULL;
    // Enqueue the root node
    QueueNode* newNode = (QueueNode*)malloc(sizeof(QueueNode));
    newNode->node = root;
    newNode->index = 0;
    newNode->next = NULL;
    head = tail = newNode;
    while (head) {
        int size = 0;
        QueueNode* temp = head;
        while (temp) {
            size++;
            temp = temp->next;
        }
        int minIndex = head->index;
        int first = 0, last = 0;
        temp = head;
        for (int i = 0; i < size; i++) {
            int currIndex = temp->index - minIndex;
            if (i == 0) first = currIndex;
            if (i == size - 1) last = currIndex;
            if (temp->node->left) {
                QueueNode* leftNode = (QueueNode*)malloc(sizeof(QueueNode));
                leftNode->node = temp->node->left;
                leftNode->index = 2 * temp->index + 1;
                leftNode->next = NULL;
                tail->next = leftNode;
                tail = leftNode;
            }
            if (temp->node->right) {
                QueueNode* rightNode = (QueueNode*)malloc(sizeof(QueueNode));
                rightNode->node = temp->node->right;
                rightNode->index = 2 * temp->index + 2;
                rightNode->next = NULL;
                tail->next = rightNode;
                tail = rightNode;
            }
            temp = temp->next;
        }
        maxWidth = (last - first + 1) > maxWidth ? (last - first + 1) : maxWidth;
        // Dequeue all nodes at the current level
        while (head && head->next) {
            QueueNode* temp2 = head;
            head = head->next;
            free(temp2);
        }
        if (head) {
            free(head);
            head = NULL;
        }
    }
    return maxWidth;
}

int main() {
    // Create a sample binary tree
    TreeNode* root = createTreeNode(1);
    root->left = createTreeNode(3);
    root->right = createTreeNode(2);
    root->left->left = createTreeNode(5);
    root->left->right = createTreeNode(3);
    root->right->right = createTreeNode(9);
    // Calculate and print the maximum width
    printf("Maximum width: %d\n", widthOfBinaryTree(root));
    return 0;
}

