#include <bits/stdc++.h>
using namespace std;

// Class definition for a binary tree node
struct TreeNode {
    int val;
    TreeNode* left;
    TreeNode* right;
    TreeNode(int x) : val(x), left(NULL), right(NULL) {}
};

// Class containing the method to find maximum width
class Solution {
public:
    // Function to compute the maximum width of binary tree
    int widthOfBinaryTree(TreeNode* root) {
        if (!root) return 0;
        int maxWidth = 0;
        queue<pair<TreeNode*, int>> q;
        q.push({root, 0});
        while (!q.empty()) {
            int size = q.size();
            int minIndex = q.front().second;
            int first = 0, last = 0;
            for (int i = 0; i < size; i++) {
                int currIndex = q.front().second - minIndex;
                TreeNode* node = q.front().first;
                q.pop();
                if (i == 0) first = currIndex;
                if (i == size - 1) last = currIndex;
                if (node->left) q.push({node->left, 2 * currIndex + 1});
                if (node->right) q.push({node->right, 2 * currIndex + 2});
            }
            maxWidth = max(maxWidth, last - first + 1);
        }
        return maxWidth;
    }
};

int main() {
    // Create a sample binary tree
    TreeNode* root = new TreeNode(1);
    root->left = new TreeNode(3);
    root->right = new TreeNode(2);
    root->left->left = new TreeNode(5);
    root->left->right = new TreeNode(3);
    root->right->right = new TreeNode(9);
    // Create solution object
    Solution sol;
    // Call the function and print the result
    cout << "Maximum width: " << sol.widthOfBinaryTree(root) << endl;
    return 0;
}

